'use client';

import React from 'react';
import Link from 'next/link';
import { usePathname, useRouter } from 'next/navigation';
import { ShoppingCart, User, Car, Package, Heart, ClipboardList, LogOut, Search, Sun, Moon, Monitor } from 'lucide-react';
import { useTheme } from 'next-themes';
import { Button } from '@/components/ui/button';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { useAuthStore } from '@/store/authStore';
import { useCartStore } from '@/store/cartStore';
import { Badge } from '@/components/ui/badge';
import LanguageSwitcher from '@/components/ui/LanguageSwitcher';
import SearchAutocomplete from '@/components/ui/SearchAutocomplete';
import { CART_MAX_DISPLAY } from '@/lib/constants';

export default function Header() {
  const pathname = usePathname();
  const { user, isAuthenticated, logout } = useAuthStore();
  const { totalItems } = useCartStore();
  const { setTheme, theme } = useTheme();

  const cartCount = totalItems();

  const navItems = [
    { name: 'Каталог', href: '/catalog', icon: Package },
    { name: 'Гараж', href: '/garage', icon: Car },
    { name: 'Избранное', href: '/favorites', icon: Heart },
    { name: 'Заказы', href: '/orders', icon: ClipboardList },
  ];

  return (
    <>
      <header className="sticky top-0 z-50 w-full border-b bg-background/95 backdrop-blur supports-[backdrop-filter]:bg-background/60">
        <div className="container mx-auto px-4 h-16 flex items-center justify-between gap-4">
          <Link href="/" className="flex items-center gap-2 font-bold text-xl tracking-tight shrink-0">
            <div className="bg-primary text-primary-foreground p-1 rounded">
              <Package className="w-6 h-6" />
            </div>
            <span className="hidden sm:inline">Auto<span className="text-primary">Parts</span></span>
          </Link>

          <div className="hidden md:flex flex-1 max-w-md relative">
            <SearchAutocomplete />
          </div>

          <div className="flex items-center gap-1 sm:gap-2">
            <nav className="hidden lg:flex items-center gap-1 mr-2">
              {navItems.map((item) => (
                <Link 
                  key={item.href} 
                  href={item.href}
                  className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${
                    pathname === item.href 
                      ? 'bg-accent text-accent-foreground' 
                      : 'text-muted-foreground hover:text-foreground hover:bg-accent'
                  }`}
                >
                  {item.name}
                </Link>
              ))}
            </nav>

            <div className="flex items-center gap-1 sm:gap-2 border-l pl-2">
              <Link href="/cart">
                <Button variant="ghost" size="icon" className="relative">
                  <ShoppingCart className="h-5 w-5" />
                  {cartCount > 0 && (
                    <Badge className="absolute -top-1 -right-1 h-5 w-5 p-0 flex items-center justify-center text-[10px]">
                    {cartCount > CART_MAX_DISPLAY ? '99+' : cartCount}
                  </Badge>
                )}
              </Button>
            </Link>

            <LanguageSwitcher />

            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <Button variant={isAuthenticated ? 'default' : 'ghost'} size="icon">
                  <User className="h-5 w-5" />
                </Button>
              </DropdownMenuTrigger>
                <DropdownMenuContent align="end">
                  <DropdownMenuItem onClick={() => setTheme('light')}>
                    <Sun className="mr-2 h-4 w-4" /> Светлая
                  </DropdownMenuItem>
                  <DropdownMenuItem onClick={() => setTheme('dark')}>
                    <Moon className="mr-2 h-4 w-4" /> Темная
                  </DropdownMenuItem>
                  <DropdownMenuItem onClick={() => setTheme('system')}>
                    <Monitor className="mr-2 h-4 w-4" /> Системная
                  </DropdownMenuItem>
                </DropdownMenuContent>
              </DropdownMenu>

              <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <Button variant={isAuthenticated ? 'default' : 'ghost'} size="icon">
                    <User className="h-5 w-5" />
                  </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent align="end" className="w-56">
                  {isAuthenticated ? (
                    <>
                      <DropdownMenuLabel>
                        {user?.full_name || user?.email || 'Пользователь'}
                        <br />
                        <span className="text-xs text-muted-foreground font-normal capitalize">{user?.role}</span>
                      </DropdownMenuLabel>
                      <DropdownMenuSeparator />
                      <DropdownMenuItem asChild>
                        <Link href="/profile"><User className="mr-2 h-4 w-4" /> Профиль</Link>
                      </DropdownMenuItem>
                      <DropdownMenuItem asChild>
                        <Link href="/garage"><Car className="mr-2 h-4 w-4" /> Мой гараж</Link>
                      </DropdownMenuItem>
                      <DropdownMenuItem asChild>
                        <Link href="/favorites"><Heart className="mr-2 h-4 w-4" /> Избранное</Link>
                      </DropdownMenuItem>
                      <DropdownMenuItem asChild>
                        <Link href="/orders"><ClipboardList className="mr-2 h-4 w-4" /> Заказы</Link>
                      </DropdownMenuItem>
                      {['admin','manager','operator'].includes(user?.role ?? '') && (
                        <>
                          <DropdownMenuSeparator />
                          <DropdownMenuItem asChild className="text-primary font-medium">
                            <Link href="/admin"><Package className="mr-2 h-4 w-4" /> Админ-панель</Link>
                          </DropdownMenuItem>
                        </>
                      )}
                      <DropdownMenuSeparator />
                      <DropdownMenuItem className="text-destructive" onClick={logout}>
                        <LogOut className="mr-2 h-4 w-4" /> Выйти
                      </DropdownMenuItem>
                    </>
                  ) : (
                    <>
                      <DropdownMenuLabel>Мой аккаунт</DropdownMenuLabel>
                      <DropdownMenuSeparator />
                      <DropdownMenuItem asChild>
                        <Link href="/auth/login">Войти</Link>
                      </DropdownMenuItem>
                      <DropdownMenuItem asChild>
                        <Link href="/auth/register">Регистрация</Link>
                      </DropdownMenuItem>
                    </>
                  )}
                </DropdownMenuContent>
              </DropdownMenu>
            </div>
          </div>
        </div>
      </header>

      <nav className="fixed bottom-0 left-0 right-0 z-50 border-t bg-background lg:hidden flex items-center justify-around py-2 safe-area-bottom">
        {navItems.map((item) => (
          <Link 
            key={item.href} 
            href={item.href}
            className={`flex flex-col items-center gap-1 px-3 py-1 rounded-md transition-colors ${
              pathname === item.href ? 'text-primary' : 'text-muted-foreground'
            }`}
          >
            <item.icon className="w-5 h-5" />
            <span className="text-[10px]">{item.name}</span>
          </Link>
        ))}
        <Link href="/catalog/search" className={`flex flex-col items-center gap-1 px-3 py-1 rounded-md transition-colors ${
          pathname === '/catalog/search' ? 'text-primary' : 'text-muted-foreground'
        }`}>
          <Search className="w-5 h-5" />
          <span className="text-[10px]">Поиск</span>
        </Link>
        <Link href="/cart" className={`flex flex-col items-center gap-1 px-3 py-1 rounded-md transition-colors ${
          pathname === '/cart' ? 'text-primary' : 'text-muted-foreground'
        }`}>
          <div className="relative">
            <ShoppingCart className="w-5 h-5" />
            {cartCount > 0 && (
              <Badge className="absolute -top-2 -right-2 h-4 w-4 p-0 flex items-center justify-center text-[8px]">
                {cartCount > CART_MAX_DISPLAY ? '99+' : cartCount}
              </Badge>
            )}
          </div>
          <span className="text-[10px]">Корзина</span>
        </Link>
      </nav>
    </>
  );
}
